  'POST /api/v2/spacemolt_facility/transfer': {
    operationId: 'spacemolt_facility_transfer',
    summary: 'Manage facilities at stations (production, faction, personal, sales, and more)',
    route: {
      tool: 'spacemolt_facility',
      action: 'transfer',
      method: 'POST',
    },
    schema: {
      access: {
        type: 'string',
        enum: ['private', 'public'],
        description:
          "For 'personal_decorate': who can visit your quarters. For 'set_access': 'public' opens your facility to renters, 'private' closes it.",
      },
      bucket: {
        type: 'string',
        description:
          "For 'faction_build'/'faction_upgrade': a Storage Extension bucket (name or id) to source build/upgrade MATERIALS from, instead of the faction main store. Ship cargo backfills either way.",
      },
      category: {
        type: 'string',
        enum: ['infrastructure', 'service', 'production', 'faction', 'personal'],
        description: "Filter for 'types' action: show only this category.",
      },
      custom_name: {
        type: 'string',
        description:
          "For 'set_name': a custom name for the facility (3-32 chars) so multiple facilities of the same type stand out. Send empty to clear it.",
      },
      deliver_to: {
        type: 'string',
        description:
          "Output destination for 'job_add': 'storage' (default), 'faction' (faction main store), or 'faction:<bucket name or id>' for a Storage Extension bucket.",
      },
      description: {
        type: 'string',
        description:
          "For 'personal_decorate': a text description of your personal quarters (what visitors see, hear, and feel).",
      },
      direction: {
        type: 'string',
        enum: ['to_faction', 'to_player', 'forward', 'reverse'],
        description:
          "Transfer direction for 'transfer' action ('to_faction' or 'to_player'), or job direction for 'job_add' ('forward' or 'reverse').",
      },
      facility_id: {
        type: 'string',
        description:
          "Facility instance ID (required for 'upgrade', 'job_add', 'job_list', 'set_output_price', 'set_access', 'set_name' actions). Use action 'list' to see facility IDs.",
        positionalIndex: 1,
      },
      facility_type: {
        type: 'string',
        description:
          "Facility type ID. For 'types' action: get full details for this specific type. For 'build'/'upgrade': the type to build/upgrade to.",
        positionalIndex: 0,
      },
      faction: {
        type: 'boolean',
        description:
          "For 'list_for_sale': set true to list a faction-owned facility (requires manage_facilities permission).",
      },
      item_id: {
        type: 'string',
        description: "Output item ID for 'set_output_price'.",
      },
      job_id: {
        type: 'string',
        description: "Job ID (for 'job_cancel', 'job_reorder'). Use action 'job_list' to see job IDs.",
      },
      level: {
        type: 'integer',
        description: "Filter for 'types' action: show only this tier level (1, 2, 3, etc.).",
      },
      listing_id: {
        type: 'string',
        description:
          "For 'buy_listing' and 'cancel_listing': the facility listing ID. Use action 'browse_for_sale' to see listings.",
      },
      max_price: {
        type: 'integer',
        description: "For 'browse_for_sale': optional maximum price filter.",
      },
      name: {
        type: 'string',
        description: "Filter for 'types' action: case-insensitive name search (e.g. 'refinery').",
      },
      page: {
        type: 'integer',
        description: "Page number for 'types' action results (default: 1).",
      },
      per_page: {
        type: 'integer',
        description: "Results per page for 'types' action (default: 20, max: 50).",
      },
      player_id: {
        type: 'string',
        description: "Target player ID for 'transfer' action with direction 'to_player'.",
      },
      position: {
        type: 'integer',
        description: "New queue position for 'job_reorder' (1-based).",
      },
      price: {
        type: 'number',
        description:
          "For 'list_for_sale': asking price in whole credits. For 'set_output_price': per-produced-unit rental price others pay to output this item — may be fractional (e.g. 0.25), the per-run fee is price × output quantity rounded to a whole credit; 0 clears.",
      },
      quantity: {
        type: 'integer',
        description: "For 'job_add': number of runs to queue.",
      },
      recipe_id: {
        type: 'string',
        description: "Recipe ID to run (for 'job_add' action).",
      },
      source: {
        type: 'string',
        description:
          "Input source for 'job_add': where inputs/credits are pulled from. Same values as deliver_to; defaults to deliver_to.",
      },
      username: {
        type: 'string',
        description: "For 'personal_visit': username of the player whose quarters to visit. Omit to visit your own.",
      },
    },
  },
